def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Group triples by subject to handle multiple predicates about the same entity
    subject_data = {}
    for t in triples:
        if t.subject not in subject_data:
            subject_data[t.subject] = []
        subject_data[t.subject].append(t)

    # Get the main subject (most common subject)
    main_subject = max(subject_data.keys(), key=lambda k: len(subject_data[k]))
    main_triples = subject_data[main_subject]

    # Build predicate information without repeating subject
    parts = []
    for t in main_triples:
        pred = t.predicate
        obj = t.object

        if pred == "birthPlace":
            part = f"was born in {obj}"
        elif pred == "birthDate":
            part = f"was born on {obj}"
        elif pred == "birthYear":
            part = f"was born in {obj}"
        elif pred == "deathPlace":
            part = f"died in {obj}"
        elif pred == "deathDate":
            part = f"died on {obj}"
        elif pred == "deathYear":
            part = f"died in {obj}"
        elif pred == "nationality":
            part = f"has {obj} nationality"
        elif pred == "party":
            part = f"belongs to the {obj} party"
        elif pred == "office":
            part = f"held the office of {obj}"
        elif pred == "successor":
            part = f"was succeeded by {obj}"
        elif pred == "predecessor":
            part = f"was preceded by {obj}"
        elif pred == "spouse":
            part = f"was married to {obj}"
        elif pred == "residence":
            part = f"resides at {obj}"
        elif pred == "region":
            part = f"is from the region of {obj}"
        elif pred == "country":
            part = f"is from {obj}"
        elif pred == "capital":
            part = f"has capital {obj}"
        elif pred == "largestCity":
            part = f"has largest city {obj}"
        elif pred == "currency":
            part = f"uses {obj} as currency"
        elif pred == "language":
            part = f"speaks {obj}"
        elif pred == "officialLanguage":
            part = f"official language is {obj}"
        elif pred == "leader":
            part = f"is led by {obj}"
        elif pred == "battle":
            part = f"participated in the {obj}"
        elif pred == "almaMater":
            part = f"studied at {obj}"
        elif pred == "profession":
            part = f"worked as a {obj}"
        elif pred == "religion":
            part = f"follows {obj}"
        elif pred == "militaryBranch":
            part = f"served in the {obj}"
        elif pred == "militaryRank":
            part = f"held the rank of {obj}"
        elif pred == "state":
            part = f"is from {obj}"
        elif pred == "award":
            part = f"received the {obj}"
        elif pred == "activeYearsStartDate":
            part = f"started in {obj}"
        elif pred == "activeYearsEndDate":
            part = f"ended in {obj}"
        else:
            part = f"{pred} {obj}"

        parts.append(part)

    # Join parts into one complex sentence with main subject at the beginning
    if not parts:
        return ""

    if len(parts) == 1:
        return f"{main_subject} {parts[0]}."
    else:
        # Use commas and 'and' for the last part
        if len(parts) == 2:
            return f"{main_subject} {parts[0]} and {parts[1]}."
        else:
            return f"{main_subject} {', '.join(parts[:-1])}, and {parts[-1]}."

